WHERE 1=1

	AND REQ_DT = #{REQ_DT}


	AND PRIORITY_CD = #{PRIORITY_CD}


	AND PROC_TYPE_CD = #{PROC_TYPE_CD}


	AND SR_TITLE LIKE '%' || UPPER(#{SR_TITLE}) || '%'


	AND SR_ID = #{SR_ID}


	AND SR_SEQ LIKE '%' || #{SR_SEQ} || '%'


	AND SR_TYPE_CD LIKE '%' || #{SR_TYPE_CD} || '%'

ORDER BY SR_ID DESC, SR_SEQ DESC

