mapper.insert:

	SELECT COALESCE(
		(SELECT SUBSTRING(MAX(SR_ID), 1, 9) || LPAD(CAST(SUBSTRING(MAX(SR_ID), 10, 4) AS INT) + 1, 4, '0')
		FROM TB_SR
		WHERE SUBSTRING(SR_ID, 4 ,6) = VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMM'))
		, 'PSR' || VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMM') || '0001')
	FROM "SYSIBM".SYSDUMMY1

INSERT INTO TB_SR (
	TB_SRID
	,SR_ID
	,SR_SEQ
	,SR_TITLE
	,REQ_USER_ID
	,REQ_PHONE
	,REQ_EMAIL
	,REQ_DT
	,PROC_USER_ID
	,PROC_DT
	,PROC_TYPE_CD
	,START_DT
	,PRIORITY_CD
	,REASON
	,ATTACH_ID
	,PERSONGROUP
	,REG_USER_ID
	,REG_DT
) VALUES (
 	NEXTVAL FOR TB_SRIDSEQ
	, #{SR_ID}
	, #{SR_SEQ}
	, #{SR_TITLE}
	, #{REQ_USER_NM}
	, #{REQ_PHONE}
	, #{REQ_EMAIL}
	, DATE(TO_DATE(REPLACE(#{REQ_DT}, '/', ''), 'YYYYMMDD'))
	, #{PROC_USER_ID}
	, #{PROC_DT}
	, '001'
	, DATE(TO_DATE(REPLACE(#{START_DT}, '/', ''), 'YYYYMMDD'))
	, #{PRIORITY_CD}
	, #{REASON}
	, #{ATTACH_ID}
	, #{PERSONGROUP}
	, #{REG_USER_ID}
	, CURRENT TIMESTAMP
)


	SELECT MAX(SR_SEQ)
