INSERT INTO TB_SR (
	TB_SRID
	,SR_ID
	,SR_SEQ
	,SR_TITLE
	,REQ_USER_ID
	,REQ_PHONE
	,REQ_EMAIL
	,REQ_DT
	,PROC_USER_ID
	,PROC_DT
	,PROC_TYPE_CD
	,START_DT
	,PRIORITY_CD
	,REASON
	,ATTACH_ID
	,PERSONGROUP
	,REG_USER_ID
	,REG_DT
) VALUES (
 	NEXTVAL FOR TB_SRIDSEQ
	, #{SR_ID}
	, (SELECT COALESCE(MAX(SR_SEQ), 0) + 1 FROM TB_SR WHERE SR_ID = #{SR_ID})
	, #{SR_TITLE}
	, #{REQ_USER_NM}
	, #{REQ_PHONE}
	, #{REQ_EMAIL}
	, DATE(TO_DATE(REPLACE(#{REQ_DT}, '/', ''), 'YYYYMMDD'))
	, #{PROC_USER_ID}
	, #{PROC_DT}
	, '001'
	, DATE(TO_DATE(REPLACE(#{START_DT}, '/', ''), 'YYYYMMDD'))
	, #{PRIORITY_CD}
	, #{REASON}
	, #{ATTACH_ID}
	, #{PERSONGROUP}
	, #{REG_USER_ID}
	, CURRENT TIMESTAMP
)

