UPDATE TB_SR SET
	PROC_TYPE_CD = #{PROC_TYPE_CD}
	, UPD_USER_ID = #{UPD_USER_ID}
	, UPD_DT = CURRENT TIMESTAMP
WHERE SR_ID = #{SR_ID}
AND SR_SEQ = #{SR_SEQ}

UPDATE TB_SR_LIST
SET PROC_TYPE_CD = #{PROC_TYPE_CD}
WHERE SR_ID = #{SR_ID}
AND SR_SEQ = #{SR_SEQ}
AND ORDER_NO = #{ORDER_NO}

